:root {
  --card-bg: #1a1d2e;
  --card-border: #2e3150;
  --header-bg: #22263d;
  --footer-bg: #1e2138;
  --label-color: #7b82aa;
  --total-color: #ffffff;
  --badge-bg: #1a3a2a;
  --badge-text: #34d27b;
  --asset-name-color: #dde1f5;
  --asset-ticker-color: #7b82aa;
  --asset-price-color: #c8ccee;
  --up-color: #34d27b;
  --down-color: #f04f5a;
  --bar-bg: #2e3150;
  --bar-btc: #f7931a;
  --bar-eth: #627eea;
  --bar-sol: #9945ff;
  --bar-dot: #e6007a;
  --icon-btc-bg: #2e2010;
  --icon-btc-color: #f7931a;
  --icon-eth-bg: #101828;
  --icon-eth-color: #627eea;
  --icon-sol-bg: #1e1030;
  --icon-sol-color: #9945ff;
  --icon-dot-bg: #2a0818;
  --icon-dot-color: #e6007a;
  --divider-color: #2e3150;
  --stat-value-color: #dde1f5;
  --accent-color: #9945ff;
  --positive-color: #34d27b;
}

.portfolio-card {
  width: 500px;
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  overflow: hidden;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: var(--header-bg);
  padding: 16px 20px;
  border-bottom: 1px solid var(--card-border);
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.label {
  font-size: 11px;
  font-weight: 500;
  color: var(--label-color);
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.total-value {
  font-size: 26px;
  font-weight: 700;
  color: var(--total-color);
  line-height: 1.1;
}

.header-right {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
}

.change-badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 14px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 20px;
}

.change-label {
  font-size: 11px;
  color: var(--label-color);
}

.asset-list {
  display: flex;
  flex-direction: column;
  gap: 0;
  padding: 8px 0;
}

.asset-row {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-bottom: 1px solid var(--card-border);
}

.asset-row:last-child {
  border-bottom: none;
}

.asset-icon {
  width: 36px;
  height: 36px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  font-weight: 700;
  flex-shrink: 0;
}

.btc {
  background: var(--icon-btc-bg);
  color: var(--icon-btc-color);
}

.eth {
  background: var(--icon-eth-bg);
  color: var(--icon-eth-color);
}

.sol {
  background: var(--icon-sol-bg);
  color: var(--icon-sol-color);
}

.dot {
  background: var(--icon-dot-bg);
  color: var(--icon-dot-color);
}

.asset-info {
  display: flex;
  flex-direction: column;
  gap: 1px;
  width: 76px;
  flex-shrink: 0;
}

.asset-name {
  font-size: 13px;
  font-weight: 600;
  color: var(--asset-name-color);
}

.asset-ticker {
  font-size: 11px;
  font-weight: 500;
  color: var(--asset-ticker-color);
}

.asset-bar-wrap {
  flex: 1;
  height: 6px;
  background: var(--bar-bg);
  border-radius: 99px;
  overflow: hidden;
}

.asset-bar {
  height: 100%;
  border-radius: 99px;
}

.bar-btc {
  width: 72%;
  background: var(--bar-btc);
}

.bar-eth {
  width: 55%;
  background: var(--bar-eth);
}

.bar-sol {
  width: 38%;
  background: var(--bar-sol);
}

.bar-dot {
  width: 18%;
  background: var(--bar-dot);
}

.asset-values {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 1px;
  flex-shrink: 0;
  width: 72px;
}

.asset-price {
  font-size: 13px;
  font-weight: 600;
  color: var(--asset-price-color);
}

.asset-change {
  font-size: 11px;
  font-weight: 600;
}

.asset-change.up {
  color: var(--up-color);
}

.asset-change.down {
  color: var(--down-color);
}

.card-footer {
  display: flex;
  align-items: center;
  background: var(--footer-bg);
  border-top: 1px solid var(--card-border);
  padding: 12px 20px;
  gap: 0;
}

.footer-stat {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
  align-items: center;
}

.footer-stat:first-child {
  align-items: flex-start;
}

.footer-stat:last-child {
  align-items: flex-end;
}

.stat-label {
  font-size: 10px;
  font-weight: 500;
  color: var(--label-color);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.stat-value {
  font-size: 13px;
  font-weight: 700;
  color: var(--stat-value-color);
}

.stat-value.accent {
  color: var(--accent-color);
}

.stat-value.positive {
  color: var(--positive-color);
}

.footer-divider {
  width: 1px;
  height: 32px;
  background: var(--divider-color);
  margin: 0 12px;
}
